import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { CartProvider } from './context/CartContext';
import './styles/global.css';

// Pages (to be created)
import Home from './pages/Home';
import Checkout from './pages/Checkout';
import OrderSuccess from './pages/OrderSuccess';

// Components
import Navbar from './components/Navbar';

// Admin Pages
import AdminLayout from './layouts/AdminLayout';
import Dashboard from './pages/admin/Dashboard';
import ManageOrders from './pages/admin/ManageOrders';
import ManageProducts from './pages/admin/ManageProducts';

function App() {
  return (
    <CartProvider>
      <Router>
        <div className="app-container">
            <Routes>
              {/* Public Routes */}
              <Route path="/" element={<><Navbar /><main className="container mt-4 mb-4"><Home /></main></>} />
              <Route path="/checkout" element={<><Navbar /><main className="container mt-4 mb-4"><Checkout /></main></>} />
              <Route path="/order-success/:orderId" element={<><Navbar /><main className="container mt-4 mb-4"><OrderSuccess /></main></>} />

              {/* Admin Routes */}
              <Route path="/admin" element={<AdminLayout />}>
                <Route index element={<Dashboard />} />
                <Route path="orders" element={<ManageOrders />} />
                <Route path="products" element={<ManageProducts />} />
              </Route>
            </Routes>
        </div>
      </Router>
    </CartProvider>
  );
}

export default App;

import React from 'react';
import { Link } from 'react-router-dom';
import { ShoppingCart } from 'lucide-react';
import { useCart } from '../context/CartContext';

const Navbar = () => {
  const { totalItems } = useCart();

  return (
    <nav style={styles.nav}>
      <div className="container flex justify-between items-center" style={{ height: '100%' }}>
        <Link to="/" style={styles.logo}>
          <img src="/banner.png" alt="Menu Kedai Mie Ayam Chili Oil" style={styles.bannerImg} />
        </Link>
        
        <Link to="/checkout" style={styles.cartContainer}>
          <ShoppingCart size={24} />
          {totalItems > 0 && (
            <span style={styles.badge}>{totalItems}</span>
          )}
        </Link>
      </div>
    </nav>
  );
};

const styles = {
  nav: {
    backgroundColor: '#1a1a1a',
    position: 'sticky',
    top: 0,
    zIndex: 100,
    boxShadow: '0 2px 10px rgba(0,0,0,0.3)',
    overflow: 'hidden',
  },
  logo: {
    display: 'flex',
    alignItems: 'center',
    textDecoration: 'none',
    height: '100%',
  },
  bannerImg: {
    height: '60px',
    objectFit: 'contain',
  },
  cartContainer: {
    position: 'relative',
    padding: '8px',
    color: '#fff',
  },
  badge: {
    position: 'absolute',
    top: '0',
    right: '0',
    backgroundColor: 'var(--primary)',
    color: '#fff',
    fontSize: '0.75rem',
    fontWeight: 'bold',
    borderRadius: '50%',
    width: '20px',
    height: '20px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
  }
};

export default Navbar;

import React from 'react';
import { Plus } from 'lucide-react';

const ProductCard = ({ product, onAddClick }) => {
  return (
    <div className="animate-fade" style={styles.card}>
      <img src={product.imageUrl} alt={product.name} style={styles.image} />
      <div style={styles.content}>
        <div style={styles.header}>
          <h3 style={styles.title}>{product.name}</h3>
          <span style={styles.price}>Rp {product.basePrice.toLocaleString()}</span>
        </div>
        <p style={styles.desc}>{product.description}</p>
        <button 
          onClick={() => onAddClick(product)} 
          style={styles.addButton}
        >
          <Plus size={20} /> Tambah
        </button>
      </div>
    </div>
  );
};

const styles = {
  card: {
    backgroundColor: 'var(--bg-card)',
    borderRadius: 'var(--radius)',
    overflow: 'hidden',
    boxShadow: 'var(--shadow)',
    marginBottom: '1rem',
    display: 'flex',
    flexDirection: 'column',
  },
  image: {
    width: '100%',
    height: '180px',
    objectFit: 'cover',
  },
  content: {
    padding: '1rem',
  },
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'start',
    marginBottom: '0.5rem',
  },
  title: {
    fontSize: '1.125rem',
    fontWeight: '700',
    flex: 1,
  },
  price: {
    fontWeight: '800',
    color: 'var(--primary)',
    marginLeft: '0.5rem',
  },
  desc: {
    fontSize: '0.875rem',
    color: 'var(--text-muted)',
    marginBottom: '1rem',
    display: '-webkit-box',
    WebkitLineClamp: 2,
    WebkitBoxOrient: 'vertical',
    overflow: 'hidden',
  },
  addButton: {
    width: '100%',
    backgroundColor: 'var(--text-main)',
    color: '#fff',
    padding: '0.75rem',
    borderRadius: '8px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '8px',
    fontWeight: '600',
    fontSize: '0.875rem',
  }
};

export default ProductCard;

import React, { useState } from 'react';
import { X, Plus, Minus } from 'lucide-react';

const ToppingModal = ({ product, toppings, onClose, onAdd }) => {
  const [quantity, setQuantity] = useState(1);
  const [selectedToppings, setSelectedToppings] = useState([]);

  const toggleTopping = (topping) => {
    setSelectedToppings(prev =>
      prev.some(t => t.id === topping.id)
        ? prev.filter(t => t.id !== topping.id)
        : [...prev, topping]
    );
  };

  const isSelected = (toppingId) => selectedToppings.some(t => t.id === toppingId);

  const totalPrice = (product.basePrice + selectedToppings.reduce((acc, t) => acc + t.price, 0)) * quantity;

  return (
    <div style={styles.overlay} onClick={onClose}>
      <div className="animate-fade" style={styles.modal} onClick={e => e.stopPropagation()}>
        <div style={styles.header}>
          <h2 style={styles.title}>Kustomisasi Pesanan</h2>
          <button type="button" onClick={onClose} style={styles.closeBtn}><X /></button>
        </div>

        <div style={styles.body}>
          {/* Product Info */}
          <div style={styles.productInfo}>
            <img src={product.imageUrl} alt={product.name} style={styles.thumb} />
            <div>
              <h3 style={{ fontWeight: 700 }}>{product.name}</h3>
              <p style={{ color: 'var(--primary)', fontWeight: 800 }}>Rp {product.basePrice.toLocaleString()}</p>
            </div>
          </div>

          {/* Toppings */}
          {toppings.length > 0 && (
            <div style={styles.section}>
              <h4 style={styles.sectionTitle}>Pilih Topping (Opsional)</h4>
              {toppings.map(topping => (
                <label key={topping.id} style={{
                  ...styles.toppingItem,
                  backgroundColor: isSelected(topping.id) ? 'rgba(211, 47, 47, 0.05)' : 'transparent',
                }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                    <input
                      type="checkbox"
                      checked={isSelected(topping.id)}
                      onChange={() => toggleTopping(topping)}
                      style={styles.checkbox}
                    />
                    <span style={{ fontWeight: isSelected(topping.id) ? 600 : 400 }}>{topping.name}</span>
                  </div>
                  <span style={{ fontSize: '0.875rem', fontWeight: 600, color: 'var(--primary)' }}>+Rp {topping.price.toLocaleString()}</span>
                </label>
              ))}
            </div>
          )}

          {/* Quantity Stepper */}
          <div style={styles.quantitySection}>
            <h4 style={styles.sectionTitle}>Jumlah</h4>
            <div style={styles.stepper}>
              <button
                type="button"
                onClick={() => setQuantity(Math.max(1, quantity - 1))}
                style={{ ...styles.stepBtn, opacity: quantity <= 1 ? 0.4 : 1 }}
              >
                <Minus size={18} />
              </button>
              <span style={{ fontWeight: 700, width: '36px', textAlign: 'center', fontSize: '1.125rem' }}>{quantity}</span>
              <button
                type="button"
                onClick={() => setQuantity(quantity + 1)}
                style={styles.stepBtn}
              >
                <Plus size={18} />
              </button>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div style={styles.footer}>
          <div style={styles.totalInfo}>
            <span style={{ fontSize: '0.875rem', color: 'var(--text-muted)' }}>Total Harga</span>
            <span style={{ fontSize: '1.25rem', fontWeight: 800, color: 'var(--primary)' }}>
              Rp {totalPrice.toLocaleString()}
            </span>
          </div>
          <button
            type="button"
            onClick={() => {
              onAdd(product, quantity, selectedToppings);
              onClose();
            }}
            style={styles.submitBtn}
          >
            Tambah ke Keranjang
          </button>
        </div>
      </div>
    </div>
  );
};

const styles = {
  overlay: {
    position: 'fixed',
    top: 0, left: 0, right: 0, bottom: 0,
    backgroundColor: 'rgba(0,0,0,0.6)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    zIndex: 1000,
    padding: '1rem',
  },
  modal: {
    backgroundColor: '#fff',
    width: '100%',
    maxWidth: '450px', // Fixed width for desktop
    borderRadius: '24px', // Rounded all around
    padding: '1.5rem',
    maxHeight: '90vh',
    overflowY: 'auto',
    boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)',
  },
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '1rem',
  },
  title: { fontSize: '1.125rem', fontWeight: 800 },
  closeBtn: { background: 'none', color: 'var(--text-muted)', padding: '4px' },
  body: { display: 'flex', flexDirection: 'column', gap: '1rem' },
  productInfo: { display: 'flex', gap: '0.75rem', alignItems: 'center' },
  thumb: { width: '48px', height: '48px', borderRadius: '10px', objectFit: 'cover', flexShrink: 0 },
  section: {},
  sectionTitle: { fontSize: '0.9rem', fontWeight: 700, marginBottom: '0.5rem', color: 'var(--text-main)' },
  toppingItem: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '0.6rem 0.5rem',
    borderBottom: '1px solid var(--border)',
    cursor: 'pointer',
    borderRadius: '8px',
    transition: 'background-color 0.15s ease',
  },
  checkbox: { width: '16px', height: '16px', accentColor: 'var(--primary)', cursor: 'pointer', flexShrink: 0 },
  quantitySection: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  stepper: {
    display: 'flex', alignItems: 'center', gap: '0.5rem',
    backgroundColor: '#f5f5f5', padding: '0.3rem 0.5rem', borderRadius: '12px'
  },
  stepBtn: {
    backgroundColor: '#fff', width: '30px', height: '30px', borderRadius: '8px',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    boxShadow: 'var(--shadow)', transition: 'opacity 0.2s',
  },
  footer: { marginTop: '1rem', display: 'flex', flexDirection: 'column', gap: '0.75rem', borderTop: '1px solid var(--border)', paddingTop: '1rem' },
  totalInfo: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  submitBtn: {
    width: '100%', backgroundColor: 'var(--primary)', color: '#fff',
    padding: '0.875rem', borderRadius: '12px', fontWeight: 700, fontSize: '1rem',
    transition: 'background-color 0.2s ease',
  },
};

export default ToppingModal;

import React, { createContext, useContext, useState, useEffect } from 'react';

const CartContext = createContext();

export const useCart = () => useContext(CartContext);

export const CartProvider = ({ children }) => {
  const [cart, setCart] = useState(() => {
    const savedCart = localStorage.getItem('mie-ayam-cart');
    return savedCart ? JSON.parse(savedCart) : [];
  });

  useEffect(() => {
    localStorage.setItem('mie-ayam-cart', JSON.stringify(cart));
  }, [cart]);

  const addToCart = (product, quantity, selectedToppings) => {
    const cartItemId = `${product.id}-${selectedToppings.map(t => t.id).sort().join(',')}`;
    
    setCart(prevCart => {
      const existingItemIndex = prevCart.findIndex(item => item.cartItemId === cartItemId);
      
      if (existingItemIndex > -1) {
        const newCart = [...prevCart];
        newCart[existingItemIndex] = {
          ...newCart[existingItemIndex],
          quantity: newCart[existingItemIndex].quantity + quantity
        };
        return newCart;
      } else {
        return [...prevCart, { 
          cartItemId, 
          productId: product.id, 
          name: product.name,
          basePrice: product.basePrice,
          imageUrl: product.imageUrl,
          quantity, 
          selectedToppings 
        }];
      }
    });
  };

  const removeFromCart = (cartItemId) => {
    setCart(prevCart => prevCart.filter(item => item.cartItemId !== cartItemId));
  };

  const updateQuantity = (cartItemId, delta) => {
    setCart(prevCart => prevCart.map(item => {
      if (item.cartItemId === cartItemId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const subtotal = cart.reduce((total, item) => {
    const itemToppingsTotal = item.selectedToppings.reduce((t, topping) => t + topping.price, 0);
    return total + (item.basePrice + itemToppingsTotal) * item.quantity;
  }, 0);

  const totalItems = cart.reduce((total, item) => total + item.quantity, 0);

  return (
    <CartContext.Provider value={{ 
      cart, 
      addToCart, 
      removeFromCart, 
      updateQuantity, 
      clearCart, 
      subtotal,
      totalItems
    }}>
      {children}
    </CartContext.Provider>
  );
};

import React from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';
import { LayoutDashboard, ShoppingBag, Utensils, LogOut } from 'lucide-react';

const AdminLayout = () => {
  const location = useLocation();

  const menuItems = [
    { path: '/admin', icon: <LayoutDashboard size={20} />, label: 'Dashboard' },
    { path: '/admin/orders', icon: <ShoppingBag size={20} />, label: 'Pesanan' },
    { path: '/admin/products', icon: <Utensils size={20} />, label: 'Menu' },
  ];

  return (
    <div style={styles.container}>
      {/* Sidebar */}
      <aside style={styles.sidebar}>
        <div style={styles.logo}>
          <h2 style={{ fontFamily: 'var(--font-heading)', fontSize: '1.5rem', color: 'var(--primary)' }}>
            MIE AYAM ADMIN
          </h2>
        </div>
        
        <nav style={styles.nav}>
          {menuItems.map((item) => (
            <Link 
              key={item.path} 
              to={item.path} 
              style={{
                ...styles.navItem,
                ...(location.pathname === item.path ? styles.activeNavItem : {})
              }}
            >
              {item.icon}
              {item.label}
            </Link>
          ))}
        </nav>

        <div style={styles.logout}>
          <Link to="/" style={styles.navItem}>
            <LogOut size={20} />
            Ke Toko (Pembeli)
          </Link>
        </div>
      </aside>

      {/* Main Content */}
      <main style={styles.main}>
        <div style={styles.content}>
          <Outlet />
        </div>
      </main>
    </div>
  );
};

const styles = {
  container: {
    display: 'flex',
    minHeight: '100vh',
    backgroundColor: 'var(--bg-main)',
  },
  sidebar: {
    width: '250px',
    backgroundColor: '#1a1a1a',
    color: '#fff',
    display: 'flex',
    flexDirection: 'column',
    position: 'fixed',
    height: '100vh',
  },
  logo: {
    padding: '1.5rem',
    borderBottom: '1px solid #333',
  },
  nav: {
    padding: '1rem 0',
    flex: 1,
  },
  navItem: {
    display: 'flex',
    alignItems: 'center',
    gap: '12px',
    padding: '1rem 1.5rem',
    color: '#ccc',
    textDecoration: 'none',
    transition: 'all 0.2s ease',
  },
  activeNavItem: {
    backgroundColor: 'var(--primary)',
    color: '#fff',
    borderLeft: '4px solid #fff',
  },
  logout: {
    padding: '1rem 0',
    borderTop: '1px solid #333',
  },
  main: {
    flex: 1,
    marginLeft: '250px',
    padding: '2rem',
  },
  content: {
    maxWidth: '1000px',
    margin: '0 auto',
    backgroundColor: '#fff',
    borderRadius: '12px',
    boxShadow: 'var(--shadow)',
    padding: '2rem',
    minHeight: '80vh',
  }
};

export default AdminLayout;

import React, { useState } from 'react';
import { useCart } from '../context/CartContext';
import { checkout as apiCheckout } from '../services/api';
import { useNavigate } from 'react-router-dom';
import { Trash2, ArrowRight, Loader2 } from 'lucide-react';

const Checkout = () => {
  const { cart, subtotal, removeFromCart, updateQuantity, clearCart } = useCart();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    customerName: '',
    paymentMethod: 'Online Payment (QRIS/Transfer)',
    tableNumber: '',
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (cart.length === 0) return;

    if (!formData.tableNumber) {
      alert('Mohon masukkan nomor meja Anda.');
      return;
    }

    setLoading(true);
    try {
      const orderData = {
        customerName: formData.customerName,
        customerPhone: formData.paymentMethod, 
        deliveryAddress: `Meja ${formData.tableNumber}`,
        totalAmount: subtotal,
        items: cart.map(item => ({
          productId: item.productId,
          quantity: item.quantity,
          unitPrice: item.basePrice,
          selectedToppings: item.selectedToppings
        }))
      };

      const result = await apiCheckout(orderData);
      
      if (formData.paymentMethod === 'Online Payment (QRIS/Transfer)') {
        // Handle simulation/mock token
        if (result.data.snapToken === 'mock-snap-token-123') {
          alert('Mode Simulasi: Pembayaran Berhasil!');
          clearCart();
          navigate(`/order-success/${result.data.id}`);
          return;
        }

        // Open Midtrans Snap
        window.snap.pay(result.data.snapToken, {
          onSuccess: function(response) {
            console.log('Payment success:', response);
            clearCart();
            navigate(`/order-success/${result.data.id}`);
          },
          onPending: function(response) {
            console.log('Payment pending:', response);
            clearCart();
            navigate(`/order-success/${result.data.id}`);
          },
          onError: function(response) {
            alert('Pembayaran gagal: ' + response.status_message);
            setLoading(false);
          },
          onClose: function() {
            alert('Anda menutup pembayaran sebelum selesai.');
            setLoading(false);
          }
        });
      } else {
        // Tunai di Kasir
        clearCart();
        navigate(`/order-success/${result.data.id}`);
      }
    } catch (err) {
      alert('Checkout gagal: ' + err.message);
      setLoading(false);
    }
  };

  if (cart.length === 0) return (
    <div className="text-center p-4 animate-fade">
      <h2 style={{ fontSize: '1.5rem', fontWeight: 800 }}>Keranjang Kosong</h2>
      <p style={{ color: 'var(--text-muted)', marginBottom: '2rem' }}>Kamu belum menambahkan apapun ke keranjang.</p>
      <button 
        onClick={() => navigate('/')}
        style={{ backgroundColor: 'var(--primary)', color: '#fff', padding: '1rem 2rem', borderRadius: '12px', fontWeight: 700 }}
      >
        Lihat Menu
      </button>
    </div>
  );

  return (
    <div className="animate-fade">
      <h1 style={{ fontSize: '1.75rem', fontWeight: 800, marginBottom: '2rem' }}>Checkout Pesanan</h1>

      <div style={styles.layout}>
        {/* Cart Summary */}
        <div style={styles.section}>
          <h2 style={styles.sectionTitle}>Ringkasan Pesanan</h2>
          <div style={styles.cartList}>
            {cart.map(item => (
              <div key={item.cartItemId} style={styles.cartItem}>
                <img src={item.imageUrl} alt={item.name} style={styles.itemThumb} />
                <div style={{ flex: 1 }}>
                  <h3 style={{ fontSize: '1rem', fontWeight: 700 }}>{item.name}</h3>
                  <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                    {item.selectedToppings.length > 0 
                      ? `Topping: ${item.selectedToppings.map(t => t.name).join(', ')}` 
                      : 'Tanpa Topping'}
                  </p>
                  <div style={styles.itemMeta}>
                    <div style={styles.stepper}>
                      <button type="button" onClick={() => updateQuantity(item.cartItemId, -1)} style={styles.stepBtn}>-</button>
                      <span>{item.quantity}</span>
                      <button type="button" onClick={() => updateQuantity(item.cartItemId, 1)} style={styles.stepBtn}>+</button>
                    </div>
                    <span style={{ fontWeight: 700 }}>Rp {((item.basePrice + item.selectedToppings.reduce((acc, t) => acc + t.price, 0)) * item.quantity).toLocaleString()}</span>
                  </div>
                </div>
                <button onClick={() => removeFromCart(item.cartItemId)} style={styles.removeBtn}>
                  <Trash2 size={18} />
                </button>
              </div>
            ))}
          </div>
          <div style={styles.totalRow}>
            <span>Subtotal</span>
            <span style={{ fontSize: '1.25rem', fontWeight: 800, color: 'var(--primary)' }}>Rp {subtotal.toLocaleString()}</span>
          </div>
        </div>

        {/* Checkout Form */}
        <form onSubmit={handleSubmit} style={styles.section}>
          <h2 style={styles.sectionTitle}>Informasi Pelanggan (Dine-in)</h2>
          <div style={styles.formGroup}>
            <label style={styles.label}>Nama Lengkap</label>
            <input 
              type="text" 
              name="customerName"
              required
              value={formData.customerName}
              onChange={handleInputChange}
              style={styles.input}
              placeholder="Masukkan nama Anda"
            />
          </div>
          <div style={styles.formGroup}>
            <label style={styles.label}>Nomor Meja</label>
            <input 
              type="number" 
              name="tableNumber"
              required
              value={formData.tableNumber}
              onChange={handleInputChange}
              style={styles.input}
              placeholder="Contoh: 5"
            />
          </div>
          <div style={styles.formGroup}>
            <label style={styles.label}>Metode Pembayaran</label>
            <select 
              name="paymentMethod"
              required
              value={formData.paymentMethod}
              onChange={handleInputChange}
              style={styles.input}
            >
              <option value="Online Payment (QRIS/Transfer)">Online Payment (QRIS/Transfer)</option>
              <option value="Tunai di Kasir">Tunai di Kasir</option>
            </select>
            <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: '0.5rem' }}>
              {formData.paymentMethod === 'Online Payment (QRIS/Transfer)' 
                ? '* Anda akan diarahkan ke gerbang pembayaran aman.' 
                : '* Silakan lakukan pembayaran ke kasir setelah memesan.'}
            </p>
          </div>

          <button 
            type="submit" 
            disabled={loading}
            style={{ ...styles.submitBtn, opacity: loading ? 0.7 : 1 }}
          >
            {loading ? <Loader2 className="animate-spin" /> : <>Pesan Sekarang <ArrowRight size={20} /></>}
          </button>
        </form>
      </div>
    </div>
  );
};

const styles = {
